import React from 'react'
import '@testing-library/jest-dom';
import { render, screen, fireEvent } from '@testing-library/react';
import { getCalculatedInstallments } from './utils';
import SplitPayment from './index.js';

export const testIds = {
    container: "split-payment-container",
    amount: "amount",
    plans: "plans",
    installments: "installments"
}

// -------- UNIT TEST --------

test('calculateInstallments works correctly', () => {
    const data = getCalculatedInstallments(6, 1200);

    expect(data).toHaveLength(6);
    expect(data[0].dueAmt).toBe(200);
});

// -------- COMPONENT TEST --------

test('all components loaded', () => {
    render(<SplitPayment />);
    // expect(screen.getByText(/Loading/i)).toBeInTheDocument();
    expect(screen.getByTestId(testIds.container)).toBeInTheDocument()
});

// -------- INTERACTION TEST --------

test('user can select a plan', async () => {
    render(<SplitPayment />);

    const button = await screen.findByText('12x');
    fireEvent.click(button);

    expect(button).toBeInTheDocument();
});

